from flask import Flask, request, jsonify
import psycopg2
import psycopg2.extras
import os

app = Flask(__name__)

# Database connection parameters
DB_HOST = os.getenv('DB_HOST')
DB_NAME = os.getenv('DB_NAME')
DB_USER = os.getenv('DB_USER')
DB_PASSWORD = os.getenv('DB_PASSWORD')

# Allowed tables and columns for security
ALLOWED_TABLES = {'employees', 'departments'}
ALLOWED_COLUMNS = {
    'employees': {'id', 'name', 'department_id', 'salary'},
    'departments': {'id', 'name'}
}

def get_db_connection():
    return psycopg2.connect(
        host=DB_HOST,
        dbname=DB_NAME,
        user=DB_USER,
        password=DB_PASSWORD
    )

@app.route('/query', methods=['POST'])
def query_db():
    data = request.json
    table = data.get('table')
    columns = data.get('columns', [])
    filters = data.get('filters', {})

    # Validate table name
    if table not in ALLOWED_TABLES:
        return jsonify({'error': 'Invalid table name'}), 400

    # Validate column names
    if not all(column in ALLOWED_COLUMNS[table] for column in columns):
        return jsonify({'error': 'Invalid column names'}), 400

    # Build SQL query
    column_list = ', '.join(columns)
    query = f"SELECT {column_list} FROM {table}"

    # Add filters
    filter_clauses = []
    filter_values = []
    for column, value in filters.items():
        if column in ALLOWED_COLUMNS[table]:
            filter_clauses.append(f"{column} = %s")
            filter_values.append(value)

    if filter_clauses:
        query += " WHERE " + " AND ".join(filter_clauses)

    try:
        conn = get_db_connection()
        with conn.cursor(cursor_factory=psycopg2.extras.DictCursor) as cursor:
            cursor.execute(query, filter_values)
            results = cursor.fetchall()
        conn.close()
        return jsonify([dict(row) for row in results])
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=False)